import{_ as a,c as e,o as i,ag as n}from"./chunks/framework.QPV3Ar9-.js";const u=JSON.parse('{"title":"Incus","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://www.spiritlhl.net/en/guide/incus/incus_install.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:site_name","content":"OneClickVirt"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Incus"}],["meta",{"property":"og:url","content":"https://www.spiritlhl.net/en/guide/incus/incus_install.html"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Incus"}]]},"headers":[],"relativePath":"en/guide/incus/incus_install.md","filePath":"en/guide/incus/incus_install.md","lastUpdated":1780885577000}'),t={name:"en/guide/incus/incus_install.md"};function l(p,s,o,r,h,c){return i(),e("div",null,s[0]||(s[0]=[n(`<h1 id="incus" tabindex="-1">Incus <a class="header-anchor" href="#incus" aria-label="Permalink to &quot;Incus&quot;">​</a></h1><p>If your host has no IPv6 subnet but you want to assign IPv6 addresses to containers, check the <code>Customize</code> section in the <code>Incus</code> module for <code>Attach a free IPv6 address segment to the host</code>, then attach an IPv6 subnet before installation.</p><h2 id="setting-up-virtual-memory-swap-optional-not-required" tabindex="-1">Setting up virtual memory (SWAP) (optional, not required) <a class="header-anchor" href="#setting-up-virtual-memory-swap-optional-not-required" aria-label="Permalink to &quot;Setting up virtual memory (SWAP) (optional, not required)&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If your host has limited memory and enough free disk space, add swap to reduce the risk of OOM crashes.</p></div><p>Unit conversion: Enter 1024 to generate 1G SWAP-virtual memory, virtual memory occupies hard disk space.</p><p>When the actual memory is not enough, the virtual memory will be automatically used for memory usage, but it will bring high IO usage and CPU performance.</p><p>For swap sizing guidance, refer to <a href="https://github.com/oneclickvirt/ecs/blob/master/README_NEW_USER.md" target="_blank" rel="noreferrer">this guide</a>.</p><table tabindex="0"><thead><tr><th>Physical Memory Size</th><th>Recommended SWAP Size</th></tr></thead><tbody><tr><td>≤ 2G</td><td>2x memory size</td></tr><tr><td>2G &lt; memory ≤ 8G</td><td>Equal to physical memory</td></tr><tr><td>≥ 8G</td><td>About 8G is sufficient</td></tr><tr><td>Hibernation needed</td><td>At least equal to physical memory</td></tr></tbody></table><p>The above values are only recommended settings, the actual value according to their own needs, do not blindly copy the value!</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/spiritLHLS/addswap/main/addswap.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="incus-one-click-installation-guide" tabindex="-1">Incus One-Click Installation Guide <a class="header-anchor" href="#incus-one-click-installation-guide" aria-label="Permalink to &quot;Incus One-Click Installation Guide&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If this is a new server, make sure that both <code>update</code> and <code>curl</code> are working properly before executing this script.</p></div><ul><li>Prerequisites: Ubuntu 20+ (LXD is usually preferred there), Debian 11+ (recommended), RockyLinux 9+, AlmaLinux 9+, CentOS 9+, Alpine (install bash first), Arch</li><li>During installation, you will be prompted to enter the storage pool creation path as well as the size, and all the VMs or containers you want to open end up taking up space in the storage pool</li><li>The server needs to be restarted after the environment installation process to load some default configurations</li><li>By default, lxcfs-related configuration is enabled, so that in-container querying of container information changes to information about the container itself rather than the host</li><li>This installer has been tested to work on either physical or non-physical machines</li><li>For non-interactive installation, use <code>export noninteractive=true</code> before the install command. The script will apply default choices for optional prompts</li></ul><p>Command:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/oneclickvirt/incus/main/scripts/incus_install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> incus_install.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> incus_install.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> incus_install.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>OR</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> incus_install.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Non-interactive example after downloading the script:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> noninteractive</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">true &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> incus_install.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Example of initialization configuration:</p><p>If you don&#39;t need to specify the path of a non-system disk as the default storage pool, then you can directly enter or type <code>n</code> when choosing whether to customize the storage pool path, and you don&#39;t need to specify the path.</p><p>If you need to specify the path of a non-system disk as the default pool, then you need to select <code>y</code> and enter the corresponding path (the actual absolute path of the disk you mounted).</p><p>If the corresponding disk has 18 Gigabytes of free hard disk space in addition to the occupied space and you want to open a 15 Gigabyte storage pool, follow the command line prompts to enter <code>15</code>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The process <strong>may</strong> require a <strong>manual reboot</strong> to load storage drivers into the kernel. At the end of installation, the server may <strong>automatically reboot</strong>. The first full reboot can take about 400-500 seconds.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If you plan to run more than 200 Incus containers on one server, this solution is not recommended. <code>lxcfs</code> drift can cause persistent I/O load that is hard to recover from. (This is an upstream LXC limitation.)</p></div><h2 id="uninstall-incus-environment" tabindex="-1">Uninstall Incus Environment <a class="header-anchor" href="#uninstall-incus-environment" aria-label="Permalink to &quot;Uninstall Incus Environment&quot;">​</a></h2><p>One-click uninstall of the complete Incus environment, including all containers, VMs, images, storage pools, network configurations, systemd services, packages, and related configuration files:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/oneclickvirt/incus/main/scripts/uninstall_incus.sh)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="manual-installation-optional" tabindex="-1">Manual Installation (optional) <a class="header-anchor" href="#manual-installation-optional" aria-label="Permalink to &quot;Manual Installation (optional)&quot;">​</a></h2><p>Not recommended for normal usage. Use it only when one-click scripts cannot run in your environment, or when you want to learn the base Incus installation process.</p><h3 id="disable-firewall" tabindex="-1">Disable Firewall <a class="header-anchor" href="#disable-firewall" aria-label="Permalink to &quot;Disable Firewall&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dos2unix</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> disable</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="enabling-virtual-memory-swap" tabindex="-1">Enabling Virtual Memory SWAP <a class="header-anchor" href="#enabling-virtual-memory-swap" aria-label="Permalink to &quot;Enabling Virtual Memory SWAP&quot;">​</a></h3><p>The amount of memory depends on how many instances you want to run. If you want to run 8 instances and calculate, you&#39;ll need 2GB of memory. If your actual physical memory is 512MB, you&#39;ll need an additional 1.5GB. To be cautious, allocate 2GB of virtual memory.</p><p>Execute the following commands: Enter &#39;1&#39;, then enter &#39;2048&#39;. This signifies allocating 2GB of virtual memory.</p><p>Command:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/oneclickvirt/incus/main/scripts/swap.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swap.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="installing-incus" tabindex="-1">Installing Incus <a class="header-anchor" href="#installing-incus" aria-label="Permalink to &quot;Installing Incus&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo -i</span></span>
<span class="line"><span>mkdir -p /etc/apt/keyrings/</span></span>
<span class="line"><span>curl -fsSL https://pkgs.zabbly.com/key.asc | gpg --dearmor -o /etc/apt/keyrings/zabbly.gpg</span></span>
<span class="line"><span>sh -c &#39;cat &lt;&lt;EOF &gt; /etc/apt/sources.list.d/zabbly-incus-stable.sources</span></span>
<span class="line"><span>Enabled: yes</span></span>
<span class="line"><span>Types: deb</span></span>
<span class="line"><span>URIs: https://pkgs.zabbly.com/incus/stable</span></span>
<span class="line"><span>Suites: $(. /etc/os-release &amp;&amp; echo \${VERSION_CODENAME})</span></span>
<span class="line"><span>Components: main</span></span>
<span class="line"><span>Architectures: $(dpkg --print-architecture)</span></span>
<span class="line"><span>Signed-By: /etc/apt/keyrings/zabbly.gpg</span></span>
<span class="line"><span>EOF&#39;</span></span>
<span class="line"><span>apt-get update</span></span>
<span class="line"><span>apt-get install incus -y</span></span>
<span class="line"><span>incus -h</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p>If no errors occur, continue with:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>incus admin init</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>For standard options, keep the defaults.</p><p>Choose the size of the physical disk (hint: select the default option with a minimum of 1GB). Generally, I fill in the available disk space minus the memory size, then multiply by 0.95 and round down. Here, I entered 10GB.</p><p>When prompted about automatic image updates, choose <code>no</code> to avoid unnecessary resource usage.</p>`,44)]))}const k=a(t,[["render",l]]);export{u as __pageData,k as default};
